import { createStore } from 'vuex'
import { getUserInfo } from '@/api/user' 
import { publicRequest } from '@/utils/request'
import router from '@/router'
import { showToast } from '@/components/ToastMessage'
import request from '@/utils/request'
import { auth } from '@/api/auth'

// Token 相关常量
const TOKEN_CONFIG = {
  // 有效期配置
  NORMAL_EXPIRATION_TIME: 2 * 60 * 60 * 1000,  // 普通登录时token有效期2小时
  REMEMBER_EXPIRATION_TIME: 7 * 24 * 60 * 60 * 1000,  // 记住我时token有效期7天
  REFRESH_INTERVAL: 20 * 60 * 1000,  // 刷新间隔20分钟
  REFRESH_THRESHOLD: 30 * 60 * 1000,  // 刷新阈值30分钟

  // 存储键名配置
  STORAGE_KEYS: {
    ACCESS_TOKEN: 'access_token',
    REFRESH_TOKEN: 'refresh_token',
    EXPIRATION: 'token_expiration',
    REMEMBER_ME: 'remember_me'
  }
}

let refreshInterval = null
let isRefreshingToken = false
let refreshSubscribers = []

// Token 刷新订阅机制
const addRefreshSubscriber = (callback) => {
  refreshSubscribers.push(callback)
}

const onTokenRefreshed = (token) => {
  refreshSubscribers.forEach(callback => callback(token))
  refreshSubscribers = []
}

/**
 * 短信验证码场
 * @enum {string}
 */
export const SMS_SCENE = {
  REGISTER: 'register',
  LOGIN: 'login',
  RESET_PASSWORD: 'reset_password',
  CHANGE_PHONE: 'change_phone',
  BIND_PHONE: 'bind_phone'
}

/**
 * Vuex Store 配置
 * @type {import('vuex').StoreOptions}
 */
export default createStore({
  state: {
    user: null,
    isAuthenticated: false,
    accessToken: null,
    refreshToken: null,
    tokenExpiration: null,
    userPhone: null,
    userId: null,
    userAvatar: null,
    rememberMe: false,
    isHandlingExpiration: false
  },

  getters: {
    getFullMediaUrl: () => (path) => {
      if (!path) return require('@/assets/images/default-avatar.png')
      if (path.startsWith('http')) return path
      return `${process.env.VUE_APP_API_URL}${path}`
    },
    getUserInfo: (state) => {
      return state.user || {
        uid: state.userId,
        phone: state.userPhone,
        avatar: state.userAvatar
      }
    },
    isAuthenticated: state => state.isAuthenticated,
    getAccessToken: state => state.accessToken,
    getUserPhone: state => state.userPhone,
    getUserId: state => state.userId,
    getUserAvatar: (state) => {
      try {
        // 尝试从多个位置获取头像
        const avatar = state.userAvatar || 
                      state.user?.avatar || 
                      localStorage.getItem('user_avatar')

        console.log('Getting avatar:', {
          stateAvatar: state.userAvatar,
          userAvatar: state.user?.avatar,
          localStorageAvatar: localStorage.getItem('user_avatar'),
          selected: avatar
        })

        if (!avatar) {
          return require('@/assets/images/default-avatar.png')
        }

        // 如果是完整的 URL，直接返回
        if (avatar.startsWith('http')) {
          return avatar
        }

        // 使用 VUE_APP_API_URL
        const fullUrl = `${process.env.VUE_APP_API_URL}${avatar}`
        console.log('Full avatar URL:', fullUrl)
        return fullUrl
      } catch (error) {
        console.error('Error in getUserAvatar:', error)
        return require('@/assets/images/default-avatar.png')
      }
    },
    wechatLoginStatus: state => state.wechatLoginStatus,
    wechatLoginError: state => state.wechatLoginError,
  },

  mutations: {
    SET_AUTH_DATA(state, { tokens, remember, phone, expiration }) {
      if (tokens) {
        state.accessToken = tokens.access
        state.refreshToken = tokens.refresh
        state.tokenExpiration = expiration
        state.isAuthenticated = true
        state.rememberMe = remember
        state.userPhone = phone

        const { STORAGE_KEYS } = TOKEN_CONFIG
        localStorage.setItem(STORAGE_KEYS.ACCESS_TOKEN, tokens.access)
        localStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN, tokens.refresh)
        localStorage.setItem(STORAGE_KEYS.EXPIRATION, expiration.toString())
        localStorage.setItem(STORAGE_KEYS.REMEMBER_ME, remember.toString())
        localStorage.setItem('account_phone', phone)
      }
    },

    SET_USER_INFO(state, userInfo) {
      try {
        console.log('更新用户信息状态:', userInfo)

        // 基本信息更新
        state.user = {
          ...state.user,
          ...userInfo,
          uid: userInfo.uid || state.user?.uid,
          username: userInfo.username || state.user?.username,
          phone: userInfo.phone || state.user?.phone,
          avatar: userInfo.avatar, // 直接使用服务器返回的头像
          basic_info: {
            ...(state.user?.basic_info || {}),
            ...(userInfo.basic_info || {})
          }
        }

        // 更新头像
        if (userInfo.avatar) {
          state.userAvatar = userInfo.avatar
          localStorage.setItem('user_avatar', userInfo.avatar)
        }

        // 更新其他信息
        if (userInfo.phone) {
          state.userPhone = userInfo.phone
        }

        if (userInfo.uid) {
          state.userId = userInfo.uid
          localStorage.setItem('user_id', userInfo.uid)
        }

        console.log('用户信息更新完成:', {
          user: state.user,
          avatar: state.userAvatar,
          phone: state.userPhone,
          uid: state.userId
        })
      } catch (error) {
        console.error('更新用户信息状态失败:', error)
      }
    },

    CLEAR_AUTH(state) {
      // 清除所有状态
      state.userInfo = null
      state.isAuthenticated = false
      state.accessToken = null
      state.refreshToken = null
      state.tokenExpiration = null
      state.userPhone = null
      state.userId = null
      state.userAvatar = null  // 清除头像状态
      state.rememberMe = false

      // 清除定时器
      if (refreshInterval) {
        clearInterval(refreshInterval)
        refreshInterval = null
      }

      // 清除 TOKEN_CONFIG 中定义的存储项
      const { STORAGE_KEYS } = TOKEN_CONFIG
      Object.values(STORAGE_KEYS).forEach(key => {
        localStorage.removeItem(key)
      })

      // 清除其他相关存储项
      const additionalKeys = [
        'account_phone',
        'redirectPath',
        'user_id',
        'user_avatar'  // 确保清除头像
      ]

      // 从 localStorage 和 sessionStorage 都清除
      additionalKeys.forEach(key => {
        localStorage.removeItem(key)
        sessionStorage.removeItem(key)
      })

      // 确保清除头像相关的存储
      localStorage.removeItem('user_avatar')
      state.userAvatar = null
    },

    setUserInfo(state, userData) {
      console.log('setUserInfo 接收到的数据:', userData)

      const user = userData.user || userData
      const basicInfo = userData.basic_info || {}

      console.log('解析后的数据:', {
        user,
        basicInfo,
        originalData: userData
      })

      state.user = {
        ...user,
        ...basicInfo
      }

      // 更新头像
      const newAvatar = basicInfo.avatar || user.avatar
      console.log('头像信息:', {
        fromBasicInfo: basicInfo.avatar,
        fromUser: user.avatar,
        selected: newAvatar,
        oldAvatar: state.userAvatar
      })

      state.userAvatar = newAvatar

      // 保存到 localStorage
      if (state.userAvatar) {
        localStorage.setItem('user_avatar', state.userAvatar)
        console.log('保存到 localStorage:', {
          avatar: state.userAvatar,
          savedAvatar: localStorage.getItem('user_avatar')
        })
      }

      console.log('Store 更新完成:', {
        finalUser: state.user,
        finalAvatar: state.userAvatar,
        fullAvatarUrl: process.env.VUE_APP_API_URL + state.userAvatar
      })
    }
  },
  actions: {
    async checkAuth({ dispatch, commit }) {
      try {
        const { STORAGE_KEYS } = TOKEN_CONFIG
        const token = localStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN)
        const refreshToken = localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN)
        const expiration = localStorage.getItem(STORAGE_KEYS.EXPIRATION)
        const rememberMe = localStorage.getItem(STORAGE_KEYS.REMEMBER_ME) === 'true'
        const phone = localStorage.getItem('account_phone')
        const savedAvatar = localStorage.getItem('user_avatar')
        const savedUid = localStorage.getItem('user_id')
        const savedUsername = localStorage.getItem('username')

        if (!token || !refreshToken || !expiration) {
          commit('CLEAR_AUTH')
          return false
        }

        const now = Date.now()
        const expirationTime = parseInt(expiration)
        const timeToExpire = expirationTime - now

        if (timeToExpire > TOKEN_CONFIG.REFRESH_THRESHOLD) {
          // 恢复认证状态
          commit('SET_AUTH_DATA', {
            tokens: {
              access: token,
              refresh: refreshToken
            },
            expiration: expirationTime,
            remember: rememberMe,
            phone
          })

          // 如果有保存的基本信息，先恢复它们
          if (savedAvatar || savedUid || savedUsername) {
            commit('SET_USER_INFO', {
              avatar: savedAvatar,
              uid: savedUid,
              username: savedUsername,
              phone
            })
          }

          // 然后获取最新的用户信息
          try {
            const response = await auth.getUserInfo()
            if (response.data?.code === 200) {
              const userInfo = response.data.data
              console.log('Fetched user info:', userInfo)

              commit('SET_USER_INFO', {
                ...userInfo,
                phone: phone || userInfo.phone
              })
            }
          } catch (error) {
            console.error('Failed to fetch user info:', error)
          }

          return true
        }

        // 如果距离过期不到30分钟，尝试刷新token
        try {
          const newToken = await dispatch('refreshToken')
          if (newToken) {
            await dispatch('fetchUserInfo')
            return true
          }
        } catch (error) {
          console.error('Token refresh failed:', error)
          if (error.response?.status === 401) {
            router.push('/login?expired=true')
          }
        }

        commit('CLEAR_AUTH')
        return false
      } catch (error) {
        console.error('Check auth error:', error)
        commit('CLEAR_AUTH')
        return false
      }
    },

    async initAuth({ commit, dispatch }) {
      try {
        // 清除可能存在的旧定时器
        if (refreshInterval) {
          clearInterval(refreshInterval)
          refreshInterval = null
        }

        const result = await dispatch('checkAuth')

        if (result) {
          // 设置时器
          refreshInterval = setInterval(async () => {
            await dispatch('checkAuth')
          }, TOKEN_CONFIG.REFRESH_INTERVAL)
        }

        return result
      } catch (error) {
        console.error('Init auth error:', error)
        commit('CLEAR_AUTH')
        return false
      }
    },

    async fetchUserInfo({ commit }) {
      try {
        const response = await request({
          url: '/api/v1/users/profile/basic/',
          method: 'get'
        })

        if (!response.data) {
          throw new Error('获取用户信息失败：无数据返回')
        }

        const userData = response.data

        // 构建用户信息对象，确保包含头像
        const userInfo = {
          ...userData,
          avatar: userData.avatar,  // 确保头像字段存在
          profile: {
            ...(userData.profile || {}),
            avatar: userData.avatar  // 在 profile 中也设置头像
          }
        }

        // 更新用户信息
        commit('SET_USER_INFO', userInfo)

        // 如果有头像，单独保存
        if (userData.avatar) {
          localStorage.setItem('user_avatar', userData.avatar)
        }

        return userInfo
      } catch (error) {
        // 如果获取失败，尝试使用保存的头像
        const savedAvatar = localStorage.getItem('user_avatar')
        if (savedAvatar) {
          commit('SET_USER_INFO', { avatar: savedAvatar })
        }
        throw error
      }
    },

    async loginWithPassword({ commit, dispatch }, { tokens, remember, phone }) {
      try {
        // 计算过期时间
        const now = Date.now()
        const expiration = remember ? 
          now + TOKEN_CONFIG.REMEMBER_EXPIRATION_TIME :
          now + TOKEN_CONFIG.NORMAL_EXPIRATION_TIME

        // 先更新认证状态
        commit('SET_AUTH_DATA', {
          tokens,
          remember,
          phone,
          expiration
        })

        // 立即获取用户基本信息
        try {
          const userResponse = await request({
            url: '/api/v1/users/profile/basic/',
            method: 'get',
            headers: {
              'Authorization': `Bearer ${tokens.access}`
            }
          })

          if (userResponse.data) {
            const userData = userResponse.data

            // 更新用户信息，包括头像
            commit('SET_USER_INFO', {
              ...userData,
              avatar: userData.avatar
            })
          }
        } catch (error) {
          console.error('Failed to fetch user profile after login:', error)
          if (error.response) {
            console.error('Error response:', error.response.data)
          }
        }

        return true
      } catch (error) {
        console.error('Login failed:', error)
        commit('CLEAR_AUTH')
        throw error
      }
    },

    async refreshToken({ commit, state }) {
      if (isRefreshingToken) {
        return new Promise((resolve) => {
          addRefreshSubscriber(token => {
            resolve(token)
          })
        })
      }

      try {
        isRefreshingToken = true
        const refreshToken = state.refreshToken || localStorage.getItem('refresh_token')
        const rememberMe = localStorage.getItem(TOKEN_CONFIG.STORAGE_KEYS.REMEMBER_ME) === 'true'

        if (!refreshToken) {
          throw new Error('No refresh token available')
        }

        const response = await auth.refreshToken({ refresh: refreshToken })

        // 使用保存的 rememberMe 状态计算的期时间
        const now = Date.now()
        const newExpirationTime = rememberMe ? 
          now + TOKEN_CONFIG.REMEMBER_EXPIRATION_TIME : 
          now + TOKEN_CONFIG.NORMAL_EXPIRATION_TIME

        // 更新 state 和 localStorage
        commit('SET_AUTH_DATA', {
          tokens: {
            access: response.data.access,
            refresh: response.data.refresh || refreshToken
          },
          expiration: newExpirationTime,
          remember: rememberMe,
          phone: state.userPhone || localStorage.getItem('account_phone')
        })

        onTokenRefreshed(response.data.access)
        return response.data.access

      } catch (error) {
        console.error('Token refresh failed:', error.response?.data || error.message)

        if (error.response?.status === 401) {
          commit('CLEAR_AUTH')
          router.push('/login?expired=true')
        } else {
          commit('CLEAR_AUTH')
        }
        throw error
      } finally {
        isRefreshingToken = false
      }
    },
    async logout({ commit, state }) {
      try {
        // 先清除本地状态
        commit('CLEAR_AUTH')

        // 尝试调用退出登录 API
        try {
          await auth.logout()
        } catch (apiError) {
          // 即使 API 调用失败，也继续执行
          console.warn('Logout API call failed, but local state was cleared:', apiError)
        }

        // 重定向到登录页
        router.push({
          path: '/login',
          query: { source: 'logout' }
        })

        return true
      } catch (error) {
        console.error('Logout process failed:', error)
        // 确保状态被清除
        commit('CLEAR_AUTH')

        // 即使出错也重定向到登录页
        router.push({
          path: '/login',
          query: { source: 'error' }
        })

        throw error
      }
    },

    async loginWithToken({ commit, dispatch }, token) {
      try {
        const expirationTime = new Date().getTime() + TOKEN_CONFIG.EXPIRATION_TIME

        commit('SET_AUTH_DATA', {
          tokens: { access: token },
          expirationTime,
          remember: false
        })

        await dispatch('fetchUserInfo')
        return true
      } catch (error) {
        commit('CLEAR_AUTH')
        throw error
      }
    },

    async handleTokenExpired({ commit, state }) {
      if (state.isHandlingExpiration) {
        return
      }

      state.isHandlingExpiration = true

      try {
        const currentPath = router.currentRoute.value.fullPath
        const isLoginPage = currentPath === '/login'

        // 先清除认证信息
        commit('CLEAR_AUTH')

        // 保存重定向路径（如果不是登录页）
        if (!isLoginPage) {
          localStorage.setItem('redirectPath', currentPath)
          showToast('登录已过期，请重新登录', 'warning')

          await router.push({
            path: '/login',
            query: { 
              redirect: currentPath,
              source: 'expired'
            }
          })
        }
      } catch (error) {
        console.error('Error during token expiration handling:', error)
      } finally {
        state.isHandlingExpiration = false
      }
    },

    async login({ commit }, { token, user }) {
      try {
        // 先保存 token
        commit('SET_AUTH_DATA', {
          tokens: { 
            access: token.access,
            refresh: token.refresh 
          },
          expiration: new Date().getTime() + TOKEN_CONFIG.NORMAL_EXPIRATION_TIME,
          remember: false,
          phone: user.phone
        })

        // 更新用户信息
        commit('SET_USER_INFO', {
          ...user,
          basic_info: user.basic_info || {}
        })

        return true
      } catch (error) {
        console.error('Failed to process login:', error)
        commit('CLEAR_AUTH')
        throw error
      }
    },

    async updateUserInfo({ commit }) {
      try {
        console.log('开始更新用户信息...')
        const response = await auth.getUserInfo()

        if (response.data?.code === 200) {
          const userInfo = response.data.data
          console.log('获取到最新用户信息:', userInfo)

          // 直接使用服务器返回的用户信息更新状态
          commit('SET_USER_INFO', userInfo)

          // 确保头像 URL 被正确保存
          if (userInfo.avatar) {
            localStorage.setItem('user_avatar', userInfo.avatar)
          }

          return userInfo
        }
      } catch (error) {
        console.error('更新用户信息失败:', error)
        throw error
      }
    },

    async setUserInfo({ commit, dispatch }, userInfo) {
      try {
        console.log('setUserInfo action received:', userInfo)

        // 处理用户信息
        const processedInfo = {
          ...userInfo,
          avatar: userInfo.avatar || '/default-avatar.png',
          username: userInfo.username || `Flybird${userInfo.phone?.slice(-4)}`,
          uid: userInfo.uid
        }

        // 更新用户信息
        commit('SET_USER_INFO', processedInfo)

        // 获取最新的用户信息（包括简历分值等）
        try {
          const response = await auth.getUserInfo()
          if (response.data?.code === 200) {
            const fullUserInfo = response.data.data
            console.log('Full user info fetched:', fullUserInfo)

            commit('SET_USER_INFO', {
              ...fullUserInfo,
              avatar: processedInfo.avatar // 保持新上传的头像
            })
          }
        } catch (error) {
          console.error('Failed to fetch updated user info:', error)
        }

        return processedInfo
      } catch (error) {
        console.error('setUserInfo action error:', error)
        return Promise.reject(error)
      }
    },

    async loginAfterRegister({ commit, dispatch }, { tokens, user }) {
      try {
        console.log('Processing registration data:', { tokens, user })

        // 设置认证数据
        const expiration = Date.now() + TOKEN_CONFIG.NORMAL_EXPIRATION_TIME
        commit('SET_AUTH_DATA', {
          tokens,
          expiration,
          remember: false,
          phone: user.phone
        })

        // 先用注册返回的用户信息更新 store
        commit('SET_USER_INFO', {
          ...user,
          avatar: user.avatar || '/default-avatar.png'
        })

        // 获取完整的用户信息
        try {
          const response = await auth.getUserInfo()
          if (response.data?.code === 200) {
            const fullUserInfo = response.data.data
            console.log('Full user info after registration:', fullUserInfo)

            commit('SET_USER_INFO', {
              ...fullUserInfo,
              phone: user.phone // 确保保留手机号
            })
          }
        } catch (error) {
          console.error('Failed to fetch full user info after registration:', error)
        }

        return user
      } catch (error) {
        console.error('Login after register failed:', error)
        throw error
      }
    }
  }
